import{_ as e,o as t,c as o,a2 as i}from"./chunks/framework.BiT4WeDN.js";const p=JSON.parse(`{"title":"Known Limitations","description":"What Yeast doesn't support yet","frontmatter":{"title":"Known Limitations","description":"What Yeast doesn't support yet"},"headers":[],"relativePath":"docs/known-limitations.md","filePath":"docs/known-limitations.md"}`),n={name:"docs/known-limitations.md"};function r(s,a,l,h,d,m){return t(),o("div",null,[...a[0]||(a[0]=[i('<h1 id="known-limitations" tabindex="-1">Known Limitations <a class="header-anchor" href="#known-limitations" aria-label="Permalink to &quot;Known Limitations&quot;">​</a></h1><p>This page documents known limitations in Yeast v1.</p><h2 id="platform-limitations" tabindex="-1">Platform Limitations <a class="header-anchor" href="#platform-limitations" aria-label="Permalink to &quot;Platform Limitations&quot;">​</a></h2><h3 id="linux-only" tabindex="-1">Linux Only <a class="header-anchor" href="#linux-only" aria-label="Permalink to &quot;Linux Only&quot;">​</a></h3><p>Yeast only runs on Linux. It does not support:</p><ul><li>macOS</li><li>Windows</li><li>WSL2 (experimental)</li></ul><h3 id="x86-64-only" tabindex="-1">x86_64 Only <a class="header-anchor" href="#x86-64-only" aria-label="Permalink to &quot;x86_64 Only&quot;">​</a></h3><p>Yeast only supports x86_64 (AMD64) architecture.</p><h3 id="no-nested-virtualization" tabindex="-1">No Nested Virtualization <a class="header-anchor" href="#no-nested-virtualization" aria-label="Permalink to &quot;No Nested Virtualization&quot;">​</a></h3><p>Yeast VMs cannot run other VMs inside them.</p><h2 id="networking-limitations" tabindex="-1">Networking Limitations <a class="header-anchor" href="#networking-limitations" aria-label="Permalink to &quot;Networking Limitations&quot;">​</a></h2><h3 id="single-network" tabindex="-1">Single Network <a class="header-anchor" href="#single-network" aria-label="Permalink to &quot;Single Network&quot;">​</a></h3><p>Yeast v1 supports only one private lab network per project.</p><h3 id="no-dhcp" tabindex="-1">No DHCP <a class="header-anchor" href="#no-dhcp" aria-label="Permalink to &quot;No DHCP&quot;">​</a></h3><p>Private networks use static IPs only.</p><h3 id="no-router" tabindex="-1">No Router <a class="header-anchor" href="#no-router" aria-label="Permalink to &quot;No Router&quot;">​</a></h3><p>Private networks are flat L2 segments.</p><h3 id="no-bridge-mode" tabindex="-1">No Bridge Mode <a class="header-anchor" href="#no-bridge-mode" aria-label="Permalink to &quot;No Bridge Mode&quot;">​</a></h3><p>Yeast uses SLIRP for management and socket multicast for lab networks.</p><h2 id="vm-limitations" tabindex="-1">VM Limitations <a class="header-anchor" href="#vm-limitations" aria-label="Permalink to &quot;VM Limitations&quot;">​</a></h2><h3 id="no-windows-guests" tabindex="-1">No Windows Guests <a class="header-anchor" href="#no-windows-guests" aria-label="Permalink to &quot;No Windows Guests&quot;">​</a></h3><p>Yeast does not support Windows VMs.</p><h3 id="no-gpu-passthrough" tabindex="-1">No GPU Passthrough <a class="header-anchor" href="#no-gpu-passthrough" aria-label="Permalink to &quot;No GPU Passthrough&quot;">​</a></h3><p>Yeast does not support GPU passthrough.</p><h3 id="limited-resource-allocation" tabindex="-1">Limited Resource Allocation <a class="header-anchor" href="#limited-resource-allocation" aria-label="Permalink to &quot;Limited Resource Allocation&quot;">​</a></h3><p>VMs are limited to:</p><ul><li>Maximum 8 GB RAM per VM</li><li>Maximum 4 CPUs per VM</li><li>Maximum 100 GB disk per VM</li></ul><h2 id="provisioning-limitations" tabindex="-1">Provisioning Limitations <a class="header-anchor" href="#provisioning-limitations" aria-label="Permalink to &quot;Provisioning Limitations&quot;">​</a></h2><h3 id="no-idempotent-shell-commands" tabindex="-1">No Idempotent Shell Commands <a class="header-anchor" href="#no-idempotent-shell-commands" aria-label="Permalink to &quot;No Idempotent Shell Commands&quot;">​</a></h3><p>Shell commands in <code>provision</code> run on every provisioning trigger.</p><h3 id="no-remote-file-provisioning" tabindex="-1">No Remote File Provisioning <a class="header-anchor" href="#no-remote-file-provisioning" aria-label="Permalink to &quot;No Remote File Provisioning&quot;">​</a></h3><p>Files must be local to the host.</p><h3 id="no-template-variables" tabindex="-1">No Template Variables <a class="header-anchor" href="#no-template-variables" aria-label="Permalink to &quot;No Template Variables&quot;">​</a></h3><p>There is no templating system in <code>yeast.yaml</code>.</p><h2 id="snapshot-limitations" tabindex="-1">Snapshot Limitations <a class="header-anchor" href="#snapshot-limitations" aria-label="Permalink to &quot;Snapshot Limitations&quot;">​</a></h2><h3 id="vm-must-be-stopped" tabindex="-1">VM Must Be Stopped <a class="header-anchor" href="#vm-must-be-stopped" aria-label="Permalink to &quot;VM Must Be Stopped&quot;">​</a></h3><p>You can only take or restore snapshots when the VM is stopped.</p><h3 id="per-instance-only" tabindex="-1">Per-Instance Only <a class="header-anchor" href="#per-instance-only" aria-label="Permalink to &quot;Per-Instance Only&quot;">​</a></h3><p>Snapshots are per-instance.</p><h3 id="no-incremental-snapshots" tabindex="-1">No Incremental Snapshots <a class="header-anchor" href="#no-incremental-snapshots" aria-label="Permalink to &quot;No Incremental Snapshots&quot;">​</a></h3><p>Each snapshot is a full disk copy.</p><h2 id="lifecycle-limitations" tabindex="-1">Lifecycle Limitations <a class="header-anchor" href="#lifecycle-limitations" aria-label="Permalink to &quot;Lifecycle Limitations&quot;">​</a></h2><h3 id="no-live-migration" tabindex="-1">No Live Migration <a class="header-anchor" href="#no-live-migration" aria-label="Permalink to &quot;No Live Migration&quot;">​</a></h3><p>VMs cannot be migrated between hosts while running.</p><h3 id="no-auto-start" tabindex="-1">No Auto-Start <a class="header-anchor" href="#no-auto-start" aria-label="Permalink to &quot;No Auto-Start&quot;">​</a></h3><p>VMs do not start automatically on boot.</p><h3 id="no-resource-monitoring" tabindex="-1">No Resource Monitoring <a class="header-anchor" href="#no-resource-monitoring" aria-label="Permalink to &quot;No Resource Monitoring&quot;">​</a></h3><p>Yeast does not monitor host resources.</p><h2 id="future-improvements" tabindex="-1">Future Improvements <a class="header-anchor" href="#future-improvements" aria-label="Permalink to &quot;Future Improvements&quot;">​</a></h2><p>These limitations may be addressed in future versions:</p><ul><li>Multiple private networks</li><li>DHCP support</li><li>Windows guest support (experimental)</li><li>GPU passthrough</li><li>Live snapshots</li><li>Project-wide snapshots</li><li>Auto-start on boot</li><li>Resource monitoring</li></ul><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="./troubleshooting.html">Troubleshooting</a> - Common issues and fixes</li><li><a href="./architecture.html">Architecture</a> - How Yeast works under the hood</li><li><a href="./configuration.html">Configuration</a> - yeast.yaml reference</li></ul>',53)])])}const c=e(n,[["render",r]]);export{p as __pageData,c as default};
